import React, { useEffect, useState } from "react";
import axios from "axios";
import "../../styles/ClientDashboard.css";
import { useNavigate } from "react-router-dom";

const ClientDashboard = () => {
  const [projects, setProjects] = useState([]);
  const [activeCount, setActiveCount] = useState(0);
  const [totalSpent, setTotalSpent] = useState(0);
  const [pendingCount, setPendingCount] = useState(0);
  const [completedCount, setCompletedCount] = useState(0);

  const navigate = useNavigate();

  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const token = localStorage.getItem("token");

        const res = await axios.get(
          "http://localhost:5000/api/projects/client",
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        const data = res.data || [];
        setProjects(data);

        const active = data.filter((p) => p.status === "open");
        const pending = data.filter((p) => p.status === "pending");
        const completed = data.filter((p) => p.status === "completed");

        setActiveCount(active.length);
        setPendingCount(pending.length);
        setCompletedCount(completed.length);

        const total = completed.reduce(
          (sum, p) => sum + Number(p.budget || 0),
          0
        );

        setTotalSpent(total);
      } catch (err) {
        console.error("Error fetching projects:", err);
      }
    };

    fetchProjects();
  }, []);

  return (
    <div className="dashboard-wrapper">
      <div className="dashboard-container">
        
        {/* HEADER */}
        <div className="dashboard-header">
          <div>
            <h2>Client Dashboard</h2>
            <p>Manage your projects and freelancers</p>
          </div>

          <button
            className="post-btn"
            onClick={() => navigate("/client/post-project")}
          >
            + Post New Project
          </button>
        </div>

        {/* STATS */}
        <div className="stats-grid">
          <div className="card">
            <h4>Active Projects</h4>
            <h2>{activeCount}</h2>
            <span className="green">+2 this week</span>
          </div>

          <div className="card">
            <h4>Total Spent</h4>
            <h2>₹{totalSpent}</h2>
            <span>Budget on track</span>
          </div>

          <div className="card">
            <h4>Pending Reviews</h4>
            <h2>{pendingCount}</h2>
            <span className="red">2 overdue</span>
          </div>

          <div className="card">
            <h4>Completed</h4>
            <h2>{completedCount}</h2>
            <span className="green">All rated</span>
          </div>
        </div>

        {/* RECENT PROJECTS */}
        <div className="recent-section">
          <h3>Recent Projects</h3>

          {projects.length === 0 ? (
            <p className="no-projects">No projects found.</p>
          ) : (
            projects.map((project) => (
              <div
                className="project-card"
                key={project._id || project.id}
              >
                <div>
                  <h4>{project.title}</h4>
                  <p>{project.description}</p>
                  <p className="budget">₹ {project.budget}</p>
                </div>

                <div>
                  <span className={`status ${project.status}`}>
                    {project.status}
                  </span>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default ClientDashboard;
